/**
 * Shared Types
 *
 * Re-exports all shared type definitions for the E-Menum application.
 * Import types from this module for consistent API contracts.
 *
 * @module shared/types
 *
 * @example
 * ```typescript
 * import {
 *   ApiResponse,
 *   PaginatedResponse,
 *   ApiErrorResponse,
 *   PaginationMeta,
 *   ValidationErrorDetail,
 *   ListQuery,
 *   isApiSuccess,
 * } from '@/shared/types';
 *
 * // In a controller
 * @Get('/')
 * @Authorized(['menu.view'])
 * async list(
 *   @QueryParams() query: ListQuery,
 * ): Promise<PaginatedResponse<Menu>> {
 *   const result = await this.menuService.findAll(orgId, query);
 *   return this.paginated(result);
 * }
 *
 * // In a service or utility
 * function handleApiResult<T>(response: ApiResponse<T> | ApiErrorResponse): T {
 *   if (isApiSuccess(response)) {
 *     return response.data;
 *   }
 *   throw new Error(response.error.message);
 * }
 * ```
 */

// -----------------------------------------------------------------------------
// API Response Types
// -----------------------------------------------------------------------------

export type {
  // Success responses
  ApiResponse,
  PaginatedResponse,
  PaginationMeta,

  // Error responses
  ApiErrorResponse,
  ApiError,
  ValidationErrorDetail,

  // Union types
  ApiResult,
  PaginatedResult,

  // Request types
  PaginationQuery,
  SortQuery,
  FilterOperator,
  FilterQuery,
  ListQuery,

  // HTTP types
  HttpMethod,
  HttpStatusCode,

  // Utility types
  ExtractApiData,
  ExtractPaginatedItem,
  AsyncApiResponse,
  AsyncPaginatedResponse,

  // Cursor pagination
  CursorPaginationMeta,
  CursorPaginatedResponse,
  CursorPaginationQuery,

  // Batch operations
  BatchItemResult,
  BatchResponse,
} from './api.types';

// -----------------------------------------------------------------------------
// Type Guards
// -----------------------------------------------------------------------------

export {
  isApiSuccess,
  isApiError,
  isPaginatedResponse,
} from './api.types';
